 1	import * as React from 'react';
 2	import { bindActionCreators } from 'redux';
 3	import { KialiDispatch } from 'types/Redux';
 4	import { connect } from 'react-redux';
 5	import { Tooltip, Button, ButtonVariant } from '@patternfly/react-core';
 6	import { KialiIcon } from 'config/KialiIcon';
 7	import { kialiStyle } from 'styles/StyleUtils';
 8	import { MeshToolbarActions } from 'actions/MeshToolbarActions';
 9	import { useKialiTranslation } from 'utils/I18nUtils';
10	
11	type ReduxProps = {
12	  resetSettings: () => void;
13	};
14	
15	type MeshResetProps = ReduxProps;
16	
17	const resetStyle = kialiStyle({
18	  marginLeft: '0.5rem',
19	  alignSelf: 'center'
20	});
21	
22	const MeshResetComponent: React.FC<MeshResetProps> = (props: MeshResetProps) => {
23	  const { t } = useKialiTranslation();
24	
25	  const onReset = (): void => {
26	    props.resetSettings();
27	  };
28	
29	  return (
30	    <Tooltip key="factory_reset_settings" position="bottom" content="Reset to factory settings">
31	      <Button
32	        id="mesh-factory-reset"
33	        className={resetStyle}
34	        variant={ButtonVariant.link}
35	        onClick={() => onReset()}
36	        isInline
37	      >
38	        <KialiIcon.ResetSettings />
39	        <span style={{ marginLeft: '5px' }}>{t('Reset')}</span>
40	      </Button>
41	    </Tooltip>
42	  );
43	};
44	
45	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxProps => {
46	  return {
47	    resetSettings: bindActionCreators(MeshToolbarActions.resetSettings, dispatch)
48	  };
49	};
50	
51	export const MeshReset = connect(null, mapDispatchToProps)(MeshResetComponent);

